                        const equipArray = getHistoryArray(d, ['equipment_details', 'equipmentDetails', 'equipment_damage', 'equipmentDamage', 'equipmentData']);
                        const staffArray = getHistoryArray(d, ['affected_staff', 'affectedStaff', 'staffAffected', 'staff']);
